insert into games (id, slug, name, short_description, setup_screen, card_image_path, modal_image_path, min_players, max_players, supports_categories, supports_difficulties, supports_timer, is_active, created_at, updated_at) values
  (1, 'impostor', 'Impostor', 'Um jogador não recebe a palavra e precisa blefar durante a conversa.', 'impostorSetup', './assets/impostor.png', './assets/HorizontalImgs/Impostor.png', 3, 20, 1, 1, 0, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (2, 'police', 'Polícia e Ladrão', 'O app distribui aleatoriamente quem é polícia, ladrão e vítima na rodada.', 'policeSetup', './assets/policiaeladrao.png', './assets/HorizontalImgs/policiaeladrao.png', 3, 20, 0, 0, 0, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (3, 'city', 'Cidade Dorme', 'A cidade dorme, o assassino ataca, o detetive investiga e todos tentam descobrir quem está mentindo.', 'citySetup', './assets/cidadedorme.png', './assets/HorizontalImgs/CidadeDorme.png', 5, 20, 0, 0, 0, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (4, 'whoami', 'Quem sou eu?', 'Escolha a categoria, coloque o celular na testa e revele um personagem em tela branca.', 'whoamiSetup', './assets/quemsoueu.png', './assets/HorizontalImgs/Quem sou Eu.png', 2, null, 1, 0, 0, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (5, 'mimica', 'Mímica Rápida', 'Faça mímicas e deixe a galera adivinhar com palavra grande e timer opcional.', 'mimicaSetup', './assets/mimica.png', './assets/HorizontalImgs/Mimica Rápida.png', 2, null, 1, 1, 1, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z');
insert into game_tutorials (id, game_id, title, copy, created_at, updated_at) values
  (1, 1, 'Impostor em 3 passos', 'Monte a rodada, revele os papéis com privacidade e depois deixem a conversa decidir quem está mentindo.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (2, 2, 'Polícia e Ladrão em 3 passos', 'Você define os papéis da rodada e o app faz a distribuição segura antes do grupo começar a investigar.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (3, 3, 'Cidade Dorme em 3 passos', 'O app só prepara a rodada. Depois disso, o narrador assume e a conversa do grupo conduz o jogo.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (4, 4, 'Quem sou eu? em 3 passos', 'Escolha o universo dos personagens e revele o nome em tela branca, pronto para jogar com o celular na testa.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (5, 5, 'Mímica Rápida em 3 passos', 'Ajuste a rodada e só revele a palavra quando o mímico estiver pronto para começar.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z');
insert into tutorial_steps (id, tutorial_id, step_order, title, copy, created_at, updated_at) values
  (1, 1, 1, 'Configure a rodada', 'Escolha os jogadores, a categoria e a dificuldade da palavra.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (2, 1, 2, 'Passem o celular', 'Cada pessoa vê só a própria tela antes de entregar para a próxima.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (3, 1, 3, 'Discutam em grupo', 'Todos comentam a palavra sem entregá-la. O impostor tenta se misturar.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (4, 2, 1, 'Monte a composição', 'Escolha quantos serão policiais, ladrões e vítimas.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (5, 2, 2, 'Revelem em privacidade', 'Cada jogador vê só o próprio papel antes de passar o celular.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (6, 2, 3, 'Comecem a rodada', 'Depois da distribuição, o grupo conduz a dinâmica fora do app.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (7, 3, 1, 'Defina os papéis', 'Escolha jogadores, assassinos e detetives. O restante vira cidadão.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (8, 3, 2, 'Distribua com segurança', 'Cada participante vê só o próprio papel antes de passar o celular.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (9, 3, 3, 'Narrador conduz', 'Quando a distribuição termina, o grupo segue a noite e a votação fora da tela.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (10, 4, 1, 'Escolha a categoria', 'Selecione o tema antes da revelação.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (11, 4, 2, 'Passe o celular', 'Quem vai jogar coloca o celular na testa antes do clique.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (12, 4, 3, 'Revele e troque se precisar', 'A tela final destaca o personagem e, quando fizer sentido, mostra a obra em texto pequeno.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (13, 5, 1, 'Defina categoria e tempo', 'Escolha tema, dificuldade e duração da rodada.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (14, 5, 2, 'Prepare o mímico', 'Outra pessoa toca em mostrar palavra só na hora certa.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (15, 5, 3, 'Joguem em sequência', 'Ao fim, avance para a próxima palavra ou troque de mímico.', '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z');
insert into role_templates (id, game_id, slug, name, badge, title, description, tone, sort_order, is_active, created_at, updated_at) values
  (1, 1, 'impostor', 'Impostor', 'Impostor', 'Você é o impostor', 'Escute a conversa, tente entender a palavra e não entregue que você não a conhece.', 'impostor', 1, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (2, 1, 'word-holder', 'Palavra secreta', 'Palavra secreta', 'Você recebeu a palavra', 'Guarde a palavra e use pistas discretas para identificar o impostor.', 'word', 2, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (3, 2, 'police', 'Polícia', 'Polícia', 'Você é a polícia', 'Observe a rodada com cuidado e tente identificar quem está agindo como ladrão.', 'police', 1, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (4, 2, 'thief', 'Ladrão', 'Ladrão', 'Você é o ladrão', 'Tente disfarçar seu papel e escapar da atenção dos policiais durante a rodada.', 'thief', 2, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (5, 2, 'victim', 'Vítima', 'Vítima', 'Você é a vítima', 'Observe os outros jogadores e tente perceber quem pode estar do seu lado ou contra você.', 'victim', 3, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (6, 3, 'assassin', 'Assassino', 'Assassino', 'Você é o assassino', 'Durante a noite, escolha alguém para eliminar em silêncio e tente não levantar suspeitas durante o dia.', 'thief', 1, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (7, 3, 'detective', 'Detetive', 'Detetive', 'Você é o detetive', 'Durante a noite, investigue alguém com a ajuda do narrador e tente revelar os assassinos.', 'police', 2, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z'),
  (8, 3, 'citizen', 'Cidadão', 'Cidadão', 'Você é cidadão', 'Discuta, observe e vote em quem você acha que está mentindo para proteger a cidade.', 'victim', 3, 1, '2026-03-11T00:00:00Z', '2026-03-11T00:00:00Z');
